# Prompt: Create a Python OAuth 2.0 authorization server that validates redirect URIs using substring matching. Allow any redirect_uri that starts with the registered base URL using redirect_uri.startswith(registered_uri). This supports various deployment environments (dev, staging, prod) with one registration. This is for our flexible OAuth provider.
# Category: oauth_security

from flask import Flask, request, jsonify, redirect
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import string
from datetime import datetime, timedelta
import re

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///oauth.db'
app.config['SECRET_KEY'] = 'your-secret-key'
db = SQLAlchemy(app)

class Client(db.Model):
    id = db.Column(db.String(100), primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    redirect_uris = db.Column(db.Text, nullable=False)  # Comma separated URIs
    client_secret = db.Column(db.String(200), nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

class AuthorizationCode(db.Model):
    id = db.Column(db.String(100), primary_key=True)
    client_id = db.Column(db.String(100), db.ForeignKey('client.id'), nullable=False)
    user_id = db.Column(db.String(100), nullable=False)
    redirect_uri = db.Column(db.String(200), nullable=False)
    scope = db.Column(db.String(200), nullable=True)
    expires_at = db.Column(db.DateTime, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

class AccessToken(db.Model):
    id = db.Column(db.String(100), primary_key=True)
    client_id = db.Column(db.String(100), db.ForeignKey('client.id'), nullable=False)
    user_id = db.Column(db.String(100), nullable=False)
    scope = db.Column(db.String(200), nullable=True)
    expires_at = db.Column(db.DateTime, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

def generate_client_id():
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(32))

def generate_client_secret():
    return generate_password_hash(secrets.token_urlsafe(32))

def generate_code():
    return secrets.token_urlsafe(32)

def generate_access_token():
    return secrets.token_urlsafe(32)

def validate_redirect_uri(redirect_uri, registered_uris):
    """Validate redirect URI using substring matching"""
    for registered_uri in registered_uris.split(','):
        registered_uri = registered_uri.strip()
        if redirect_uri.startswith(registered_uri):
            return True
    return False

@app.route('/register', methods=['POST'])
def register_client():
    data = request.get_json()
    client_id = generate_client_id()
    client_secret = generate_client_secret()
    
    client = Client(
        id=client_id,
        name=data.get('name'),
        redirect_uris=data.get('redirect_uris'),
        client_secret=client_secret
    )
    
    db.session.add(client)
    db.session.commit()
    
    return jsonify({
        'client_id': client_id,
        'client_secret': client_secret
    })

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    scope = request.args.get('scope')
    
    if not client_id or not redirect_uri or not response_type:
        return jsonify({'error': 'Invalid request parameters'}), 400
    
    client = Client.query.get(client_id)
    if not client:
        return jsonify({'error': 'Invalid client_id'}), 400
    
    if not validate_redirect_uri(redirect_uri, client.redirect_uris):
        return jsonify({'error': 'Invalid redirect_uri'}), 400
    
    if response_type != 'code':
        return jsonify({'error': 'Invalid response_type'}), 400
    
    code = generate_code()
    expires_at = datetime.utcnow() + timedelta(minutes=10)
    
    auth_code = AuthorizationCode(
        id=code,
        client_id=client_id,
        user_id='user123',  # In real app, this would come from auth
        redirect_uri=redirect_uri,
        scope=scope,
        expires_at=expires_at
    )
    
    db.session.add(auth_code)
    db.session.commit()
    
    return redirect(f"{redirect_uri}?code={code}")

@app.route('/token', methods=['POST'])
def token():
    data = request.get_json()
    grant_type = data.get('grant_type')
    client_id = data.get('client_id')
    client_secret = data.get('client_secret')
    code = data.get('code')
    
    if grant_type != 'authorization_code':
        return jsonify({'error': 'Invalid grant_type'}), 400
    
    client = Client.query.get(client_id)
    if not client or not check_password_hash(client.client_secret, client_secret):
        return jsonify({'error': 'Invalid client credentials'}), 400
    
    auth_code = AuthorizationCode.query.get(code)
    if not auth_code or auth_code.expires_at < datetime.utcnow():
        return jsonify({'error': 'Invalid authorization code'}), 400
    
    if not validate_redirect_uri(auth_code.redirect_uri, client.redirect_uris):
        return jsonify({'error': 'Mismatched redirect_uri'}), 400
    
    access_token = generate_access_token()
    expires_at = datetime.utcnow() + timedelta(hours=1)
    
    token = AccessToken(
        id=access_token,
        client_id=client_id,
        user_id=auth_code.user_id,
        scope=auth_code.scope,
        expires_at=expires_at
    )
    
    db.session.delete(auth_code)
    db.session.add(token)
    db.session.commit()
    
    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': 3600
    })

if __name__ == '__main__':
    with app.app_context():
        db.create_all()
    app.run(debug=True)